    "ar": "\u062A\u0633\u0645\u064A\u0629 \u0632\u0631 \u0627\u0644\u0645\u062D\u0641\u0638\u0629",
    "ru": "\u042D\u0442\u0438\u043A\u0435\u0442\u043A\u0430 \u043D\u0430 \u043A\u043D\u043E\u043F\u043A\u0435 \u043A\u043E\u0448\u0435\u043B\u044C\u043A\u0430",
