    "ru": "\u{1F3A8} \u041D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0430 \u0438 \u043E\u0444\u043E\u0440\u043C\u043B\u0435\u043D\u0438\u0435 QR-\u043A\u043E\u0434\u0430",
